const fs = require('fs');
const path = require('path');

const workDir = '/Users/orion/Documents/WorkBuddy工作空间/公众号分析';

function listDir(dir, indent = 0) {
    const items = fs.readdirSync(dir);
    for (const item of items) {
        const fullPath = path.join(dir, item);
        const stat = fs.statSync(fullPath);
        console.log('  '.repeat(indent) + (stat.isDirectory() ? '📁 ' : '📄 ') + item + (stat.isDirectory() ? '/' : ` (${(stat.size/1024).toFixed(1)} KB)`));
        if (stat.isDirectory()) {
            listDir(fullPath, indent + 1);
        }
    }
}

console.log('=== 工作目录内容 ===\n');
listDir(workDir);
